"use strict";parserFactory.register("moonquill.com",()=>new MoonqQillParser);class MoonqQillParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div#toc div.card-body div.col-1")].map(e=>MoonqQillParser.divToChapter(e))}static divToChapter(e){let t=e.querySelector("a"),r=e.nextElementSibling.querySelector("a").textContent.trim();return{sourceUrl:t.href,title:t.textContent.trim().replace("#","")+": "+r,newArc:null}}findContent(e){return e.querySelector("div#content")}extractTitleImpl(e){return e.querySelector("h1.card-header-title")}customRawDomToContentStep(e,t){this.uncommentStoryText(t)}uncommentStoryText(e){let t=[...e.childNodes].filter(e=>e.nodeType===Node.COMMENT_NODE);for(let r of t){let t=util.sanitize("<article>"+r.data+"</article>").querySelector("article");e.appendChild(t);break}}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.main-content")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#syn div.card-body")]}}